import{_ as p,C as i,o as c,c as s,j as a,a as o,E as t,a3 as u}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"道德经第一章","description":"从道、名、无、有、玄进入《道德经》的总门。","frontmatter":{"title":"道德经第一章","description":"从道、名、无、有、玄进入《道德经》的总门。","category":"guide","aliases":["道德经第一章","老子第一章","道可道","dao de jing chapter 1"],"source":["通行本《道德经》","王弼注本系统"]},"headers":[],"relativePath":"daoism/texts/dao-de-jing/chapter-01.md","filePath":"daoism/texts/dao-de-jing/chapter-01.md","lastUpdated":1778132952000}'),h={name:"daoism/texts/dao-de-jing/chapter-01.md"};function m(x,e,g,b,_,f){const l=i("DaoReadingPrelude"),n=i("DaoOriginalReading"),d=i("DaoLineGuide"),r=i("DaoKeywordCards");return c(),s("div",null,[e[0]||(e[0]=a("h1",{id:"道德经第一章",tabindex:"-1"},[o("道德经第一章 "),a("a",{class:"header-anchor",href:"#道德经第一章","aria-label":'Permalink to "道德经第一章"'},"​")],-1)),t(l,{title:"先看道与名如何开门",summary:"这一章不是急着定义“道”，而是先提醒读者：语言能引路，但不能替代源头本身。最适合的进入方式，是先读原文的气息，再看断句与关键词如何慢慢展开。",points:[{label:"先读",text:"让句子先完整落下来，不急着拆。"},{label:"再辨",text:"看无 / 有、妙 / 徼如何相对出现。"},{label:"后解",text:"最后再回到名与道的关系。"}],hint:"若是第一次读《道德经》，建议先把本章读两遍，再进入下面的逐句引读与关键词卡片。"}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[o("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),t(n,{paragraphs:["道可道，非常道。","名可名，非常名。","无名天地之始；","有名万物之母。","故常无欲，以观其妙；","常有欲，以观其徼。","此两者，同出而异名，同谓之玄。","玄之又玄，众妙之门。"]}),t(d,{lines:[{text:"道可道，非常道。",tone:"起句",guide:"能被完全说出来的道，就不是恒常的道。语言能引路，但不能替代路本身。"},{text:"名可名，非常名。",tone:"并进",guide:"能被固定下来的名，就不是恒常的名。概念一旦僵死，活的东西就被封住了。"},{text:"无名天地之始；",tone:"溯源",guide:"无名，指向天地未分、万物未名的源头状态——那是一种浑然未分的开始。"},{text:"有名万物之母。",tone:"展开",guide:"有名，万物开始被命名、被识别、被区分——世界由此展开为可分可识的样子。"},{text:"故常无欲，以观其妙；",tone:"观法一",guide:"常保持无欲的心态，更容易触到事物幽微精妙的深处。"},{text:"常有欲，以观其徼。",tone:"观法二",guide:"带着有欲的心去看，更容易看见事物的边界、轮廓和外在端倪。"},{text:"此两者，同出而异名，同谓之玄。",tone:"合拢",guide:"无和有看似两端，实则同出一源，只是名称不同。这种深远的同一，就叫「玄」。"},{text:"玄之又玄，众妙之门。",tone:"收束",guide:"深远之上再深远——不是故弄玄虚，而是说：一旦你愿意不断往深处走，那就是进入一切精妙的门。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[o("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),t(r,{title:"字词释义",items:[{term:"徼",pinyin:["jiào"],meaning:"边际、外缘、轮廓、可见之迹。",context:"常有欲，更容易看到显出来的边界与端倪。"},{term:"玄",pinyin:["xuán"],meaning:"深、幽、难以一言穷尽。",context:"不是神秘化，而是指出源头问题无法被一句话封住。"},{term:"道",pinyin:["dào"],meaning:"根本之理、运行之则，也是无法被固定语言完全包住的所指。",context:"本章先不是定义道，而是先提醒“道不可被说尽”。"},{term:"名",pinyin:["míng"],meaning:"命名、概念、标签、分别世界的方式。",context:"一旦进入“名”，世界就开始被分门别类。"},{term:"无",pinyin:["wú"],meaning:"未分、未定、尚未落入概念分别。",context:"更接近“天地之始”的源头感。"},{term:"有",pinyin:["yǒu"],meaning:"已显、已分、可识、可名。",context:"更接近万物展开之后的世界。"},{term:"妙",pinyin:["miào"],meaning:"幽微、深处、未显之妙。",context:"常无欲，才更容易见到这一层。"}]}),e[3]||(e[3]=u('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一章在说什么" tabindex="-1">象：这一章在说什么 <a class="header-anchor" href="#象-这一章在说什么" aria-label="Permalink to &quot;象：这一章在说什么&quot;">​</a></h3><p>第一章像是在给整部《道德经》立门规。</p><p>它先提醒读者：</p><ul><li>凡是可以被完全说出来的“道”，都不是终极的道</li><li>凡是可以被完全固定下来的“名”，都不是终极的名</li></ul><p>接着，它又把“无名”与“有名”展开为两种层次：</p><ul><li><code>无名</code> 更接近源头</li><li><code>有名</code> 更接近万物的展开</li></ul><p>再进一步，它指出“无欲”与“有欲”会带来不同的观看结果：</p><ul><li><code>无欲</code> 更容易见其妙</li><li><code>有欲</code> 更容易见其徼</li></ul><p>最后，它把这些看似不同的两端重新收回到一个更深的层次：同出而异名，同谓之玄。</p><h3 id="理-为什么这样说" tabindex="-1">理：为什么这样说 <a class="header-anchor" href="#理-为什么这样说" aria-label="Permalink to &quot;理：为什么这样说&quot;">​</a></h3><p>这章的关键，不是在制造玄虚，而是在提醒学习者：语言有用，但语言也有限。</p><p>人一旦开始命名，就会进入分别的世界：</p><ul><li>这是山</li><li>那是水</li><li>这是我</li><li>那是物</li></ul><p>这让世界变得可说、可分、可识别，但也容易让人把“名”误当成了实相本身。</p><p>因此，老子一开篇就先拆掉语言执着：</p><ul><li><code>无名</code> 让人更接近本始</li><li><code>有名</code> 让人看到万物如何展开</li></ul><p>这里并不是说“有名”错了，而是在说：如果只停在有名、有欲、有分别的层次，人就容易离源头越来越远。</p><p>“故常无欲，以观其妙；常有欲，以观其徼”也不是简单地赞美无欲、贬低有欲，而是在指出：不同的心态，会看到世界的不同层面。无欲更容易触到幽微之妙，有欲更容易看到外在之迹。</p><p>到了“此两者，同出而异名，同谓之玄”，老子又把前面展开的两端重新收拢：看似不同的无与有、妙与徼、源头与显现，其实同出一源。只是到了人的理解里，才被分成了不同名称。</p><p>所以“玄”并不是故作神秘，而是说：凡触及源头的问题，都深、都幽、都不是一句定义可以穷尽。</p><h3 id="用-这一章今天怎么用" tabindex="-1">用：这一章今天怎么用 <a class="header-anchor" href="#用-这一章今天怎么用" aria-label="Permalink to &quot;用：这一章今天怎么用&quot;">​</a></h3><p>这一章对今天的学习方式有直接提醒。</p><p>第一，不要急着为经典下死定义。<br> 第二，不要把语言当成终点。<br> 第三，不要把“无”和“有”学成彼此对立。<br> 第四，要学会两种观看方式并行：</p><ul><li>先以较少预设的心去感受其源头</li><li>再以结构化的方式整理其展开与层次</li></ul><p>如果把它放到今天的学习里，可以理解为：</p><ul><li><code>无名</code> 的看法，帮助我们保留开放、保留感受力</li><li><code>有名</code> 的看法，帮助我们建立概念、索引与结构</li></ul><p>两者都需要，缺一不可。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>能被完全说清的“道”，已经不是道本身；能被完全固定下来的“名”，也不是它最终的真实。</p><p>在没有命名之前，万物更接近它的本始；进入命名之后，世界开始展开成可分可识的万物。</p><p>当人放下执取与预设时，更容易看到那幽微深处的“妙”；当人带着分辨与认知去看时，更容易看到事物已经显现出来的边界、轮廓与端倪。</p><p>看似不同的“无”与“有”，其实来自同一个源头，只是名称不同、显现不同。真正的学习入口，不在抓住某个固定定义，而在愿意不断往更深处走。那道门，就是“众妙之门”。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>这一章让我最先感到的，不是抽象概念，而是一种强烈的源头感。</p><p>“无名天地之始”中的“天地之始”，让人自然感到宏大、广博，也让人意识到：这里谈的不是某个局部知识点，而是在追问万物未分之前的根。</p><p>我目前更愿意把这一章理解成：</p><ul><li><code>无名</code> 不是空无，而是未分、未定、未被概念切开的本始状态</li><li><code>有名</code> 不是错误，而是万物展开之后进入可分、可识、可说的层次</li><li><code>无欲</code> 与 <code>有欲</code> 不是价值上的绝对好坏，而是两种观看世界的方式</li></ul><p>所以真正重要的，不是站在哪一边，而是知道自己此刻是在看“源”，还是在看“流”；是在看“深处”，还是在看“轮廓”。</p><p>第一章像是在提醒学习者：不要把语言当终点，不要把名字当实相。先承认语言有边界，后面才真正进得去。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《道德经》通行本</li><li>王弼《老子注》相关系统</li></ul>',42))])}const k=p(h,[["render",m]]);export{q as __pageData,k as default};
